"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import AsciiCanvas from "./AsciiCanvas";
import { CELL_H, CELL_W } from "@/lib/ascii/shapeVectors";

/**
 * Render a classical sculpture as a live amber ASCII object.
 *
 * Input: a compact binary mesh generated by `scripts/process-sculptures.ts`
 *   ─ bytes 0-3   : magic "STA1"
 *   ─ bytes 4-7   : triangle count (uint32 LE)
 *   ─ body        : N triangles × 9 float32 vertices (36 bytes each)
 *
 * Pipeline per frame:
 *   1. Compute yaw from elapsed time (+ optional phase offset so multiple
 *      sculptures on the same page don't spin in lockstep).
 *   2. For each triangle: rotate its three vertices, project to 2D,
 *      compute the post-rotation normal via cross product, skip if
 *      back-facing (orientation-agnostic: we try both winding orders
 *      and keep whichever half of the mesh faces forward most often).
 *   3. Painter's algorithm: sort triangles by centroid depth (far first),
 *      fill each with amber at `max(dot(normal, light), 0)` intensity.
 *   4. Feed the 2D canvas into `AsciiCanvas`, which walks its cells with
 *      the 6D shape-vector picker and produces glyphs.
 *
 * Performance: at the typical mesh size (~2500 triangles) this is
 * ~150k triangle fills per second at 60fps, which the 2D canvas handles
 * well on anything modern. We `paused` the component automatically when
 * the mesh isn't loaded so we don't burn frames over a blank scene.
 */

export type SculptureAsciiProps = {
  /** URL of a .mesh.bin file. Relative to `public/`. */
  src: string;
  cols?: number;
  rows?: number;
  /** Revolutions per second of the Y-axis yaw. Default 0.05 = one rotation every 20s. */
  yawSpeed?: number;
  /** Fixed pitch (radians) so the figure is slightly above / below the viewer. */
  pitch?: number;
  /** Phase offset (radians) so peers can be out of sync. */
  phase?: number;
  /** Upfront scale multiplier on the [-1, 1] normalized mesh. */
  scale?: number;
  /** Canvas color override — resolved via AsciiCanvas helpers. */
  color?: string;
  /**
   * Glyph-cell scale (passed through to AsciiCanvas). Values < 1 shrink
   * the glyphs, giving finer detail at the same physical size — useful
   * for large backdrop sculptures where facial features should be
   * legible. Default 1.0.
   */
  cellScale?: number;
  ariaLabel?: string;
};

/** Cache so we don't re-fetch the same mesh across page navigation. */
const meshCache = new Map<string, Float32Array>();

type Vec3 = readonly [number, number, number];

/** Parse the compact binary into a Float32Array of 9-float triangles. */
function parseMesh(buf: ArrayBuffer): Float32Array {
  const view = new DataView(buf);
  const magic = String.fromCharCode(
    view.getUint8(0),
    view.getUint8(1),
    view.getUint8(2),
    view.getUint8(3),
  );
  if (magic !== "STA1") {
    throw new Error(`Expected STA1 magic, got "${magic}"`);
  }
  const count = view.getUint32(4, true);
  // Re-use the underlying buffer's body as a Float32Array (zero-copy).
  return new Float32Array(buf, 8, count * 9);
}

function slugFromSrc(src: string): string {
  const m = src.match(/\/?([^/?]+)\.mesh\.bin(?:\?.*)?$/);
  return m?.[1] ?? "default";
}

function addTri(out: number[], a: Vec3, b: Vec3, c: Vec3): void {
  out.push(a[0], a[1], a[2], b[0], b[1], b[2], c[0], c[1], c[2]);
}

function addSphere(
  out: number[],
  center: Vec3,
  radius: number,
  latSteps = 8,
  lonSteps = 12,
): void {
  const [cx, cy, cz] = center;
  for (let lat = 0; lat < latSteps; lat++) {
    const t0 = (lat / latSteps) * Math.PI;
    const t1 = ((lat + 1) / latSteps) * Math.PI;
    const y0 = Math.cos(t0) * radius;
    const y1 = Math.cos(t1) * radius;
    const r0 = Math.sin(t0) * radius;
    const r1 = Math.sin(t1) * radius;
    for (let lon = 0; lon < lonSteps; lon++) {
      const p0 = (lon / lonSteps) * Math.PI * 2;
      const p1 = ((lon + 1) / lonSteps) * Math.PI * 2;
      const a: Vec3 = [cx + Math.cos(p0) * r0, cy + y0, cz + Math.sin(p0) * r0];
      const b: Vec3 = [cx + Math.cos(p1) * r0, cy + y0, cz + Math.sin(p1) * r0];
      const c: Vec3 = [cx + Math.cos(p0) * r1, cy + y1, cz + Math.sin(p0) * r1];
      const d: Vec3 = [cx + Math.cos(p1) * r1, cy + y1, cz + Math.sin(p1) * r1];
      if (lat === 0) {
        addTri(out, a, c, d);
      } else if (lat === latSteps - 1) {
        addTri(out, a, d, b);
      } else {
        addTri(out, a, c, d);
        addTri(out, a, d, b);
      }
    }
  }
}

function sub(a: Vec3, b: Vec3): Vec3 {
  return [a[0] - b[0], a[1] - b[1], a[2] - b[2]];
}

function add(a: Vec3, b: Vec3): Vec3 {
  return [a[0] + b[0], a[1] + b[1], a[2] + b[2]];
}

function mul(v: Vec3, s: number): Vec3 {
  return [v[0] * s, v[1] * s, v[2] * s];
}

function cross(a: Vec3, b: Vec3): Vec3 {
  return [
    a[1] * b[2] - a[2] * b[1],
    a[2] * b[0] - a[0] * b[2],
    a[0] * b[1] - a[1] * b[0],
  ];
}

function normalize(v: Vec3): Vec3 {
  const len = Math.hypot(v[0], v[1], v[2]);
  if (len < 1e-6) return [0, 1, 0];
  return [v[0] / len, v[1] / len, v[2] / len];
}

function addCapsule(
  out: number[],
  start: Vec3,
  end: Vec3,
  radius: number,
  radialSegments = 10,
): void {
  const axis = sub(end, start);
  const axisLen = Math.hypot(axis[0], axis[1], axis[2]);
  if (axisLen < 1e-5) return;
  const dir = normalize(axis);
  const seed: Vec3 = Math.abs(dir[1]) < 0.9 ? [0, 1, 0] : [1, 0, 0];
  const u = normalize(cross(dir, seed));
  const v = normalize(cross(dir, u));
  for (let i = 0; i < radialSegments; i++) {
    const a0 = (i / radialSegments) * Math.PI * 2;
    const a1 = ((i + 1) / radialSegments) * Math.PI * 2;
    const r0 = add(mul(u, Math.cos(a0) * radius), mul(v, Math.sin(a0) * radius));
    const r1 = add(mul(u, Math.cos(a1) * radius), mul(v, Math.sin(a1) * radius));
    const s0 = add(start, r0);
    const s1 = add(start, r1);
    const e0 = add(end, r0);
    const e1 = add(end, r1);
    addTri(out, s0, e0, e1);
    addTri(out, s0, e1, s1);
  }
  addSphere(out, start, radius, 5, 8);
  addSphere(out, end, radius, 5, 8);
}

